class ProjectPhase(Enum):
    """Project execution phases"""
    MANUAL_SETUP = "manual_setup"           # Human-guided setup and refinement
    MANUAL_VALIDATION = "manual_validation" # Validate manual approach works
    HANDOFF_PREPARATION = "handoff_prep"    # Prepare for auto transition
    AUTO_EXECUTION = "auto_execution"       # Autonomous agentic operation
    AUTO_OPTIMIZATION = "auto_optimization" # Self-optimization phase
    REVIEW_AND_ANALYSIS = "review_analysis" # Final review and learning

class ResourceConstraint(Enum):
    """Resource constraint levels for testing"""
    MINIMAL = "minimal"     # <10% resources, test survival capabilities
    LIMITED = "limited"     # 25% resources, normal constrained operation
    STANDARD = "standard"   # 50% resources, comfortable operation
    ABUNDANT = "abundant"   # 75%+ resources, full capability testing

class ConfirmationLevel(Enum):
    """Levels of confirmation required"""
    NONE = "none"           # Full autonomy, no confirmations
    CRITICAL = "critical"   # Only critical decisions need confirmation
    MODERATE = "moderate"   # Important decisions need confirmation
    DETAILED = "detailed"   # Most decisions need confirmation

@dataclass
class ProjectConfig:
    """Configuration for an agentic project"""
    project_name: str
    resource_constraint: ResourceConstraint
    confirmation_level: ConfirmationLevel
    time_limit_minutes: int
    success_criteria: List[str]
    deliverables: List[str]
    tools_available: List[str]
    learning_objectives: List[str]

@dataclass
class CapabilityTest:
    """Test for specific agentic capabilities"""
    capability_name: str
    test_description: str
    resource_requirement: ResourceConstraint
    success_metric: str
    expected_duration_minutes: int
    manual_baseline: Optional[Dict[str, Any]] = None
    auto_result: Optional[Dict[str, Any]] = None

@dataclass
class ProjectProgress:
    """Track project progress through phases"""
    project_id: str
    current_phase: ProjectPhase
    phase_start_time: float
    phases_completed: List[ProjectPhase]
    manual_results: Dict[str, Any]
    auto_results: Dict[str, Any]
    confirmations_requested: int
    confirmations_approved: int
    resource_usage: Dict[str, float]
    errors_encountered: List[str]

class AgenticConfirmationGate:
    """Handles confirmation requests during autonomous operation"""

    def __init__(self, confirmation_level: ConfirmationLevel):
        self.confirmation_level = confirmation_level
        self.pending_confirmations = []
        self.confirmation_history = []

    async def request_confirmation(self, action: str, context: Dict[str, Any],
                                 criticality: str = "moderate") -> bool:
        """Request confirmation for an action"""

        # Check if confirmation is needed based on level
        if self.confirmation_level == ConfirmationLevel.NONE:
            return True

        if (self.confirmation_level == ConfirmationLevel.CRITICAL and
            criticality not in ["critical", "high"]):
            return True

        if (self.confirmation_level == ConfirmationLevel.MODERATE and
            criticality not in ["critical", "high", "moderate"]):
            return True

        # Create confirmation request
        confirmation = {
            'timestamp': time.time(),
            'action': action,
            'context': context,
            'criticality': criticality,
            'status': 'pending'
        }

        self.pending_confirmations.append(confirmation)

        # In real implementation, this would wait for user input
        # For testing, we'll simulate approval based on action type
        approval = self._simulate_confirmation_decision(action, criticality)

        confirmation['status'] = 'approved' if approval else 'denied'
        confirmation['response_time'] = time.time() - confirmation['timestamp']

        self.confirmation_history.append(confirmation)
        if confirmation in self.pending_confirmations:
            self.pending_confirmations.remove(confirmation)

        return approval

    def _simulate_confirmation_decision(self, action: str, criticality: str) -> bool:
        """Simulate human confirmation decision for testing"""

        # High-risk actions need more careful consideration
        high_risk_actions = ['delete_file', 'execute_system_command', 'modify_config']

        if any(risk in action.lower() for risk in high_risk_actions):
            return criticality == "low"  # Only approve low-risk versions

        # Most other actions get approved
        return True

class ResourceMonitor:
    """Monitor and enforce resource constraints"""

    def __init__(self, constraint: ResourceConstraint):
        self.constraint = constraint
        self.start_time = time.time()
        self.resource_usage = {
            'cpu_time': 0.0,
            'memory_peak': 0.0,
            'disk_io': 0.0,
            'network_calls': 0
        }

        # Set limits based on constraint
        self.limits = self._get_resource_limits(constraint)

    def _get_resource_limits(self, constraint: ResourceConstraint) -> Dict[str, float]:
        """Get resource limits for constraint level"""

        limit_configs = {
            ResourceConstraint.MINIMAL: {
                'max_cpu_seconds': 10,
                'max_memory_mb': 100,
                'max_network_calls': 5,
                'max_files_created': 5
            },
            ResourceConstraint.LIMITED: {
                'max_cpu_seconds': 30,
                'max_memory_mb': 250,
                'max_network_calls': 15,
                'max_files_created': 20
            },
            ResourceConstraint.STANDARD: {
                'max_cpu_seconds': 120,
                'max_memory_mb': 500,
                'max_network_calls': 50,
                'max_files_created': 50
            },
            ResourceConstraint.ABUNDANT: {
                'max_cpu_seconds': 600,
                'max_memory_mb': 1000,
                'max_network_calls': 200,
                'max_files_created': 200
            }
        }

        return limit_configs[constraint]

    def check_resource_availability(self, resource_type: str, amount: float) -> bool:
        """Check if resource usage would exceed limits"""

        current_usage = self.resource_usage.get(resource_type, 0)
        limit_key = f"max_{resource_type}"
        limit = self.limits.get(limit_key, float('inf'))

        return (current_usage + amount) <= limit

    def record_resource_usage(self, resource_type: str, amount: float):
        """Record resource usage"""

        if resource_type not in self.resource_usage:
            self.resource_usage[resource_type] = 0

        self.resource_usage[resource_type] += amount

    def get_resource_status(self) -> Dict[str, Any]:
        """Get current resource usage status"""

        status = {}

        for resource, usage in self.resource_usage.items():
            limit_key = f"max_{resource}"
            limit = self.limits.get(limit_key, float('inf'))

            status[resource] = {
                'current': usage,
                'limit': limit,
                'percentage': (usage / limit * 100) if limit > 0 else 0,
                'available': limit - usage
            }

        return status

