        """Create a new agentic project"""

        project_id = f"{config.project_name}_{int(time.time())}"

        # Create project directory
        project_path = self.project_directory / project_id
        project_path.mkdir(parents=True, exist_ok=True)

        # Initialize project progress
        progress = ProjectProgress(
            project_id=project_id,
            current_phase=ProjectPhase.MANUAL_SETUP,
            phase_start_time=time.time(),
            phases_completed=[],
            manual_results={},
            auto_results={},
            confirmations_requested=0,
            confirmations_approved=0,
            resource_usage={},
            errors_encountered=[]
        )

        self.projects[project_id] = progress

        # Save project configuration
        config_path = project_path / "project_config.json"
        with open(config_path, 'w') as f:
            json.dump(asdict(config), f, indent=2)

        # Create project structure
        await self._setup_project_structure(project_path, config)

        return project_id

