        if project_id not in self.projects:
            raise ValueError(f"Project {project_id} not found")

        progress = self.projects[project_id]
        progress.current_phase = ProjectPhase.MANUAL_SETUP
        progress.phase_start_time = time.time()

        project_path = self.project_directory / project_id

        # Load project config
        with open(project_path / "project_config.json", 'r') as f:
            config = json.load(f)

        print(f"🔧 Starting Manual Phase for {config['project_name']}")
        print(f"Resource Constraint: {config['resource_constraint']}")
        print(f"Time Limit: {config['time_limit_minutes']} minutes")

        # Manual execution simulation (in real system, this would be interactive)
        manual_results = await self._simulate_manual_execution(project_path, config)

        progress.manual_results = manual_results
        progress.phases_completed.append(ProjectPhase.MANUAL_SETUP)

        # Validate manual results
        validation_results = await self._validate_manual_results(project_path, manual_results)

        if validation_results['success']:
            progress.phases_completed.append(ProjectPhase.MANUAL_VALIDATION)
            print("✅ Manual phase completed successfully")
        else:
            print("❌ Manual phase needs refinement")
            print(f"Issues: {validation_results['issues']}")

        return {
            'phase': 'manual',
            'results': manual_results,
            'validation': validation_results,
            'ready_for_handoff': validation_results['success']
        }

