    async def _validate_manual_results(self, project_path: Path, manual_results: Dict[str, Any]) -> Dict[str, Any]:
        """Validate that manual approach works"""

        validation = {
            'success': True,
            'files_validated': 0,
            'files_working': 0,
            'issues': []
        }

        # Test each created file
        for file_path in manual_results['files_created']:
            validation['files_validated'] += 1

            try:
                # Simple validation - check if Python file can be imported
                if file_path.endswith('.py'):
                    # In real system, would execute and test
                    # For now, just check file exists and has content
                    path = Path(file_path)
                    if path.exists() and path.stat().st_size > 50:
                        validation['files_working'] += 1
                    else:
                        validation['issues'].append(f"File {file_path} too small or missing")
            except Exception as e:
                validation['issues'].append(f"Error validating {file_path}: {str(e)}")

        # Check overall success
        if validation['files_working'] < validation['files_validated']:
            validation['success'] = False

        return validation

    async def handoff_to_auto(self, project_id: str) -> Dict[str, Any]:
        """Prepare for and execute handoff to autonomous operation"""

        if project_id not in self.projects:
            raise ValueError(f"Project {project_id} not found")

        progress = self.projects[project_id]

        if ProjectPhase.MANUAL_VALIDATION not in progress.phases_completed:
            return {'error': 'Manual validation must be completed before handoff'}

        progress.current_phase = ProjectPhase.HANDOFF_PREPARATION
        progress.phase_start_time = time.time()

        project_path = self.project_directory / project_id

        # Load configuration
        with open(project_path / "project_config.json", 'r') as f:
            config = ProjectConfig(**json.load(f))

        print(f"🤖 Preparing handoff to autonomous operation")
        print(f"Confirmation Level: {config.confirmation_level.value}")
        print(f"Resource Constraint: {config.resource_constraint.value}")

        # Create handoff documentation
        handoff_doc = await self._create_handoff_documentation(progress, config)

        # Save handoff documentation
        with open(project_path / "handoff_documentation.json", 'w') as f:
            json.dump(handoff_doc, f, indent=2)

        progress.phases_completed.append(ProjectPhase.HANDOFF_PREPARATION)

        # Execute autonomous phase
        auto_results = await self._execute_autonomous_phase(project_id, config, handoff_doc)

        return {
            'handoff_completed': True,
            'auto_results': auto_results
        }

