            auto_results['confirmations_requested'] = len(confirmation_gate.confirmation_history)
            progress.confirmations_requested = auto_results['confirmations_requested']
            progress.confirmations_approved = len([c for c in confirmation_gate.confirmation_history if c['status'] == 'approved'])

            # Record resource usage
